noncompliant:
using System;

namespace MyLibrary // Noncompliant - missing ComVisible attribute
{
    public class MyClass
    {
    }
}

// Assembly without explicit COM visibility specification
namespace MyNamespace
{
    public class PublicClass { }
}

compliant:
using System;

[assembly: System.Runtime.InteropServices.ComVisible(false)] // Compliant

namespace MyLibrary
{
    public class MyClass
    {
    }
}

[assembly: System.Runtime.InteropServices.ComVisible(true)] // Compliant - explicitly visible to COM
namespace MyLibrary
{
    public class COMVisibleClass { }
}
